// 网络检测装饰器
import { useNetworkOnline } from '../network/detector';
import { useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';


interface UseNetworkDecoratorOptions {
    onNetworkChange: (isOnline: boolean)=> void
    emitOfflineWhenRouteChange?: boolean // 如果处于离线状态时路由发生变化，会重复触发 onNetworkChange 回调
}

export const useNetworkDecorator = ({
                                        onNetworkChange,
                                        emitOfflineWhenRouteChange = true,
                                    }: UseNetworkDecoratorOptions) => {
    const location = useLocation();
    const prevOnline = useRef<boolean>(true);
    const { isOnline } = useNetworkOnline();

    useEffect(() => {
        if (emitOfflineWhenRouteChange) {
            prevOnline.current = true;
        }
    }, [location.pathname]);

    useEffect(() => {
        if (prevOnline.current !== isOnline) {
            prevOnline.current = isOnline;
            onNetworkChange(isOnline);
        }
    }, [isOnline, location.pathname]);
};
